import{_ as l,o as i,c as r,a2 as a}from"./chunks/framework.DnrXFDHb.js";const d=JSON.parse('{"title":"🫘 黃豆追蹤日誌 — 2026-05-05","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-05.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-05.md"}'),t={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-05.md"};function e(n,o,s,u,g,c){return i(),r("div",null,[...o[0]||(o[0]=[a('<h1 id="🫘-黃豆追蹤日誌-—-2026-05-05" tabindex="-1">🫘 黃豆追蹤日誌 — 2026-05-05 <a class="header-anchor" href="#🫘-黃豆追蹤日誌-—-2026-05-05" aria-label="Permalink to &quot;🫘 黃豆追蹤日誌 — 2026-05-05&quot;">​</a></h1><blockquote><p>查詢時間（TST）：2026-05-05 09:48 Asia/Taipei ⚠️ 注意：05:00 TST = 17:00 ET（前日），CME 黃豆期貨處於 14:00-20:00 ET 休息時段，以下為 5/4 收盤及即時替代數據。</p></blockquote><hr><h2 id="_8-項追蹤指標" tabindex="-1">8 項追蹤指標 <a class="header-anchor" href="#_8-項追蹤指標" aria-label="Permalink to &quot;8 項追蹤指標&quot;">​</a></h2><h3 id="_1-usda-種植進度報告" tabindex="-1">1. USDA 種植進度報告 <a class="header-anchor" href="#_1-usda-種植進度報告" aria-label="Permalink to &quot;1. USDA 種植進度報告&quot;">​</a></h3><p><strong>狀態：🔴 有重大變化</strong></p><ul><li>截至 5/3，美國黃豆播種進度 <strong>33%</strong>，大幅優於去年 28%、五年均 23%</li><li>出苗率 <strong>13%</strong>（去年 6%、五年均 5%）</li><li>領先州：路易斯安那 84%、密西西比 77%、俄亥俄 30%（五年均 14%）、南達科塔 14%</li></ul><blockquote><p>來源：USDA Crop Progress Report via ICIS、FarmProgress（2026-05-04）</p></blockquote><h3 id="_2-巴西-阿根廷供應" tabindex="-1">2. 巴西/阿根廷供應 <a class="header-anchor" href="#_2-巴西-阿根廷供應" aria-label="Permalink to &quot;2. 巴西/阿根廷供應&quot;">​</a></h3><p><strong>狀態：🟡 有變化</strong></p><ul><li><strong>阿根廷</strong>：截至 5/3 收割進度 18.3%，已收 1160 萬噸（總產 4860 萬噸）</li><li>雖優於上季同期，但<strong>落後五年均 11 個百分點</strong></li><li>產區北部平均單產 39.6 公擔/公頃、南部 40.5 公擔/公頃，均優於歷史均值</li><li>86.3% 田間狀況正常至優良，土壤水分充足</li></ul><blockquote><p>來源：ICIS、BiofuelsDigest、Ukragroconsult（2026-05-04）</p></blockquote><h3 id="_3-尿素價格-多單訊號" tabindex="-1">3. 尿素價格 + 多單訊號 <a class="header-anchor" href="#_3-尿素價格-多單訊號" aria-label="Permalink to &quot;3. 尿素價格 + 多單訊號&quot;">​</a></h3><p><strong>狀態：🔴 有重大變化</strong></p><ul><li><strong>尿素現貨</strong>：$585/T（5/4），月跌 16.58%，但年增 22.77%</li><li><strong>FOB US Gulf 5月期貨</strong>：$631/T（5/1）</li><li><strong>FOB 中東顆粒尿素</strong>：~$795/T（4月底）</li><li>荷莫茲海峽封鎖導致4月底尿素一度飆至 $700/T（從 $455/T），隨後回落</li><li>世界銀行預估 2026 年尿素價格可能飆漲 60%，若不利情境可達 $700/T 以上</li><li><strong>對黃豆影響</strong>：化肥成本上升將壓縮農民利潤，可能影響種植決策</li></ul><blockquote><p>來源：TradingEconomics（2026-05-04）、Nairametrics（2026-05-03）、World Bank</p></blockquote><h3 id="_4-荷莫茲海峽通航狀態" tabindex="-1">4. 荷莫茲海峽通航狀態 <a class="header-anchor" href="#_4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;4. 荷莫茲海峽通航狀態&quot;">​</a></h3><p><strong>狀態：🔴 有重大變化</strong></p><ul><li>伊朗持續控制海峽交通並收取通行費，僅約 5% 戰前船運量通過</li><li>5/3 美國啟動「自由護航行動」</li><li>5/4 美報告擊沉伊朗小型船隻，局勢再度升溫</li><li><strong>對黃豆影響</strong>：全球糧食海運成本飆升，BDI 月增 32%、年增 92%</li></ul><blockquote><p>來源：Wikipedia、Cryptobriefing、Baltic Exchange（2026-05-04/05）</p></blockquote><h3 id="_5-中美貿易-中國進口" tabindex="-1">5. 中美貿易 + 中國進口 <a class="header-anchor" href="#_5-中美貿易-中國進口" aria-label="Permalink to &quot;5. 中美貿易 + 中國進口&quot;">​</a></h3><p><strong>狀態：🔴 有重大變化</strong></p><ul><li><strong>中國 3 月黃豆進口</strong>：月減但年增 14.7%，巴西占主導地位</li><li><strong>美國黃豆對中出口</strong>：受關稅限制，仍低於去年同期</li><li><strong>2025/26 承諾</strong>：中國承諾每年至少購買 2,500 萬噸美國黃豆至 2028 年</li><li><strong>FAS USDA 預測</strong>：2026-27 年度中國黃豆進口增至 1.08 億噸（+200 萬噸）</li><li><strong>但有報告指出</strong>：2026 年中國進口可能降至 8,255 萬噸（年減 26.2%）</li><li>美國最高法院關稅裁決增加不確定性</li></ul><blockquote><p>來源：Commodity-Board（2026-05-05）、SCMP、Ukragroconsult、Producer.com（2026-05-04/05）</p></blockquote><h3 id="_6-天然氣價格" tabindex="-1">6. 天然氣價格 <a class="header-anchor" href="#_6-天然氣價格" aria-label="Permalink to &quot;6. 天然氣價格&quot;">​</a></h3><p><strong>狀態：⚪ 無重大變化</strong></p><ul><li>Henry Hub 報 $2.85/MMBtu（5/5），較前日 -0.75%</li><li>5/4 現貨 $2.685（+8.0¢）</li><li>整體持穩，無重大波動</li></ul><blockquote><p>來源：TradingEconomics、Business Insider（2026-05-05）</p></blockquote><h3 id="_7-聖嬰-拉尼娜氣候風險" tabindex="-1">7. 聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#_7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;7. 聖嬰/拉尼娜氣候風險&quot;">​</a></h3><p><strong>狀態：🔴 有重大變化</strong></p><ul><li><strong>拉尼娜正在消退</strong>，5-7 月預計轉為 ENSO 中性</li><li><strong>聖嬰可能在 6-8 月形成</strong>（機率 62%），持續至年底</li><li>部分預測甚至暗示 Q4 可能出現「超級聖嬰」</li><li><strong>對黃豆影響</strong>： <ul><li>美國：聖嬰帶來涼爽潮濕夏季，有利黃豆生長，但收割期可能因暴雨受阻</li><li>南美：聖嬰通常增加巴西南部和阿根廷降雨，有利產量</li><li>印度：聖嬰可能導致季風不足，減產風險</li></ul></li><li><strong>美國 2026 黃豆播種面積</strong>：預估 8,600 萬英畝（年增 5.9%），為近年最大</li></ul><blockquote><p>來源：WMO、NOAA、DTN Progressive Farmer、Independent（2026-04/05）</p></blockquote><h3 id="_8-cbot-價格區間" tabindex="-1">8. CBOT 價格區間 <a class="header-anchor" href="#_8-cbot-價格區間" aria-label="Permalink to &quot;8. CBOT 價格區間&quot;">​</a></h3><p><strong>狀態：🔴 有重大變化</strong></p><ul><li><strong>5/4 收盤</strong>：ZSK26（5月合約）1208&#39;0 美分/蒲式耳（+1.66%）</li><li>其他報價：1195&#39;4 至 1187&#39;6（不同合約月份）</li><li>TradingEconomics 報 1,207.50 美分</li><li>多週新高，突破前期盤整區間</li><li><strong>驅動因素</strong>：地緣緊張推升生質燃料需求、阿根廷收割延遲、美國壓榨需求強勁</li></ul><blockquote><p>來源：CME Group、Barchart、TradingEconomics、ProFarmer（2026-05-04）</p></blockquote><hr><h2 id="即時現貨-現金價格" tabindex="-1">即時現貨/現金價格 <a class="header-anchor" href="#即時現貨-現金價格" aria-label="Permalink to &quot;即時現貨/現金價格&quot;">​</a></h2><ul><li><strong>美國黃豆現金收購價</strong>：$11.10-$11.79/蒲式耳（CHS/Nexus/USDA 報告，5/4）</li><li><strong>DTN 全國黃豆指數</strong>：$11.54（+21¢），全國平均基差 -69¢（相對7月期貨）</li></ul><blockquote><p>來源：CHS、Nexus Cooperative、DTN（2026-05-04）</p></blockquote><hr><h2 id="📰-即時新聞摘要-5-條" tabindex="-1">📰 即時新聞摘要（5 條） <a class="header-anchor" href="#📰-即時新聞摘要-5-條" aria-label="Permalink to &quot;📰 即時新聞摘要（5 條）&quot;">​</a></h2><ol><li><strong>USDA 播種報告超預期</strong>：美國黃豆播種 33%，大幅領先五年均 23%（ICIS, 5/4）</li><li><strong>阿根廷收割延後</strong>：18.3% 收割進度，落後五年均 11 個百分點（BiofuelsDigest, 5/4）</li><li><strong>荷莫茲海峽升溫</strong>：美伊海上衝突加劇，海運成本飆升（IBTimes, 5/5）</li><li><strong>黃豆突破盤整</strong>：CBOT 黃豆創多週新高，地緣+需求雙重驅動（ProFarmer, 5/4）</li><li><strong>聖嬰即將形成</strong>：6-8 月聖嬰機率 62%，可能影響全球黃豆產量（WMO/NOAA, 5/4）</li></ol><hr><h2 id="📊-綜合判斷" tabindex="-1">📊 綜合判斷 <a class="header-anchor" href="#📊-綜合判斷" aria-label="Permalink to &quot;📊 綜合判斷&quot;">​</a></h2><p>黃豆市場本週偏多。美國播種順利但阿根廷收割延遲，荷莫茲海峽危機持續推升運費與糧食安全擔憂。CBOT 價格突破 1200 美分關卡，短期可能測試更高。尿素價格波動、聖嬰即將形成、中美貿易不確定性為主要風險。需關注 5/12 USDA 月度供需報告。</p><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>ICIS（2026-05-04）：USDA Crop Progress 33%</li><li>BiofuelsDigest（2026-05-04）：阿根廷收割 18.3%</li><li>CME Group（2026-05-04）：ZSK26 1208&#39;0</li><li>TradingEconomics（2026-05-04）：黃豆 1,207.50 美分、尿素 $585/T</li><li>CHS/Nexus/DTN（2026-05-04）：現金 $11.10-$11.79</li><li>TradingEconomics（2026-05-05）：Henry Hub $2.85</li><li>Wikipedia/Cryptobriefing（2026-05-04/05）：荷莫茲海峽</li><li>Nairametrics/World Bank（2026-05-03）：尿素預測飆漲60%</li><li>Commodity-Board/SCMP/Ukragroconsult（2026-05-04/05）：中國黃豆進口</li><li>WMO/NOAA/Independent（2026-04/05）：聖嬰預測6-8月形成</li></ol>',49)])])}const p=l(t,[["render",e]]);export{d as __pageData,p as default};
